def parser(log: str) -> dict[str, str]:
    import json
    import re

    results: dict[str, str] = {}

    def normalize_status(status: str) -> str:
        status = (status or "").lower()
        if status in {"passed", "pass", "success"}:
            return "pass"
        if status in {"failed", "fail", "failure", "error"}:
            return "fail"
        if status in {"pending", "skipped", "todo", "disabled"}:
            return "skip"
        return ""

    def add_result(name: str, status: str, suite_name: str | None = None):
        if not name or not status:
            return
        key = name
        if key in results and suite_name:
            alt = f"{suite_name} :: {name}"
            if alt not in results:
                key = alt
            else:
                # last resort, unique suffix
                i = 2
                while f"{alt} ({i})" in results:
                    i += 1
                key = f"{alt} ({i})"
        results[key] = status

    def parse_json_obj(data):
        for suite in data.get("testResults", []):
            suite_name = suite.get("name")
            # If suite has no assertionResults but has failure, mark suite
            if not suite.get("assertionResults") and suite.get("status"):
                status = normalize_status(suite.get("status"))
                if status:
                    add_result(suite_name or "unknown suite", status, suite_name)
            for test in suite.get("assertionResults", []):
                name = test.get("fullName") or test.get("title")
                if not name:
                    # Build from ancestorTitles + title
                    ancestor = test.get("ancestorTitles") or []
                    title = test.get("title") or ""
                    if ancestor or title:
                        name = " ".join(ancestor + ([title] if title else []))
                status = normalize_status(test.get("status"))
                add_result(name, status, suite_name)

    # 1) Try full JSON parse
    data = None
    try:
        data = json.loads(log)
    except Exception:
        data = None

    # 2) Try to find largest JSON object in log
    if data is None:
        # find all candidate JSON objects and pick the largest
        candidates = []
        for match in re.finditer(r"\{.*\}", log, re.DOTALL):
            chunk = match.group(0)
            # quick heuristic: must contain "testResults"
            if '"testResults"' in chunk:
                candidates.append(chunk)
        # if none with testResults, fall back to any {}
        if not candidates:
            candidates = [m.group(0) for m in re.finditer(r"\{.*\}", log, re.DOTALL)]
        # try parsing candidates by length
        for chunk in sorted(candidates, key=len, reverse=True):
            try:
                data = json.loads(chunk)
                break
            except Exception:
                continue

    if isinstance(data, dict):
        parse_json_obj(data)

    # 3) Fallback to parsing plain Jest output symbols if still empty
    if not results:
        # Jest output: ✓ test name, ✕ test name, ○ test name
        # Also handle "PASS"/"FAIL" prefixes
        for line in log.splitlines():
            line = line.strip()
            if not line:
                continue
            m = re.match(r"^[✓✔]\s+(.*)$", line)
            if m:
                add_result(m.group(1).strip(), "pass")
                continue
            m = re.match(r"^[✕✖✗]\s+(.*)$", line)
            if m:
                add_result(m.group(1).strip(), "fail")
                continue
            m = re.match(r"^[○◌]\s+(.*)$", line)
            if m:
                add_result(m.group(1).strip(), "skip")
                continue
            m = re.match(r"^(PASS|FAIL)\s+(.+)$", line)
            if m:
                status = "pass" if m.group(1) == "PASS" else "fail"
                add_result(m.group(2).strip(), status)

    return results
